import os


def _read_lines(path):
    with open(path, "r", encoding="utf-8") as fh:
        return fh.readlines()


def os_release_summary():
    out = {}
    for line in _read_lines("/etc/os-release"):
        if "=" not in line:
            continue
        key, value = line.split("=", 1)
        out[key.strip()] = value.strip().strip('"')
    return {
        "id": out.get("ID"),
        "version_id": out.get("VERSION_ID"),
        "pretty_name": out.get("PRETTY_NAME"),
    }


def detect_python3():
    for base in ["/usr/bin", "/usr/local/bin", "/bin"]:
        if os.path.exists(base + "/python3"):
            return True
    return False


def meminfo_summary():
    data = {}
    for line in _read_lines("/proc/meminfo"):
        if ":" not in line:
            continue
        key, value = line.split(":", 1)
        data[key.strip()] = value.strip()

    def _kb_to_mb(name):
        raw = data.get(name, "0 kB").split()[0]
        return int(raw) // 1024

    return {
        "mem_total_mb": _kb_to_mb("MemTotal"),
        "mem_available_mb": _kb_to_mb("MemAvailable"),
    }


def disk_free_mb(path):
    stat = os.statvfs(path)
    return int((stat.f_bavail * stat.f_frsize) / (1024 * 1024))


def readiness_verdict(python3_present, meminfo, root_free_mb):
    reasons = []
    if not python3_present:
        reasons.append("system python3 absent")
    if meminfo.get("mem_available_mb", 0) < 64:
        reasons.append("low available memory")
    if root_free_mb < 128:
        reasons.append("low free disk on /")

    verdict = "ready"
    if meminfo.get("mem_available_mb", 0) < 64 or root_free_mb < 128:
        verdict = "warning"

    return verdict, reasons


def proof_value(a, b):
    return a + (a * b)
